fixed_code:
use std::sync::{Arc, Mutex};

struct Node {
    value: i32,
    next: Option<Arc<Mutex<Option<Box<Node>>>>>,
}

struct LinkedList {
    head: Arc<Mutex<Option<Box<Node>>>>,
}

impl LinkedList {
    fn new() -> Self {
        LinkedList { head: Arc::new(Mutex::new(None)) }
    }

    unsafe fn push(&mut self, value: i32) {
        let node = Box::new(Node { value, next: None });
        let mut head = self.head.lock().unwrap();
        *head = Some(node);
    }
}

fn main() {
    unsafe {
        let mut ll = LinkedList::new();
        ll.push(10);
    }
}
